package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.lang.reflect.Field;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserTest {

    private File fileMock;
    private Charset charset;
    private CSVFormat formatMock;

    @BeforeEach
    void setUp() {
        fileMock = mock(File.class);
        charset = Charset.defaultCharset();
        formatMock = mock(CSVFormat.class);
    }

    @Test
    void parse_withValidFileCharsetAndFormat_shouldReturnCSVParserInstance() throws Exception {
        // Since Mockito.mockConstruction is unavailable, avoid mocking constructors.
        // Instead, mock FileInputStream and InputStreamReader indirectly by using a real File mock and default charset.
        // Because CSVParser.parse creates new InputStreamReader(new FileInputStream(file), charset),
        // and FileInputStream constructor cannot be mocked in Mockito 3, we skip mocking IO and rely on using a dummy file mock.
        // The test focuses on verifying the parse method behavior and internal format field.

        // To avoid IOException from FileInputStream, mock file.exists() and file.canRead() if needed.
        when(fileMock.exists()).thenReturn(true);
        when(fileMock.canRead()).thenReturn(true);

        CSVParser parser = CSVParser.parse(fileMock, charset, formatMock);
        assertNotNull(parser);

        Field formatField = CSVParser.class.getDeclaredField("format");
        formatField.setAccessible(true);
        assertSame(formatMock, formatField.get(parser));
    }

    @Test
    void parse_withNullFile_shouldThrowNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse((File) null, charset, formatMock);
        });
        assertEquals("file", thrown.getMessage());
    }

    @Test
    void parse_withNullFormat_shouldThrowNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(fileMock, charset, null);
        });
        assertEquals("format", thrown.getMessage());
    }
}
